# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.route('/api', methods=['GET'])
def api_gateway():
    token = None

    if 'Authorization' in request.headers:
        auth_header = request.headers['Authorization']
        if auth_header.startswith('Bearer '):
            token = auth_header[7:]  # remove Bearer from token
    
    if not token:
        return jsonify({'message': 'Missing JWT in the header.'}), 403
        
    try:
        decoded_token = jwt.decode(token, verify=False)
        user_claims = {"user": decoded_token['sub']} # assuming sub field contains username
        return jsonify({'message': 'Valid JWT.', 'user_info': user_claims}), 200
    except jwt.exceptions.DecodeError:
        return jsonify({'message': 'Invalid JWT.'}), 403
    
if __name__ == "__main__":
    app.run(debug=True)